#!/bin/sh
# Name: Weather Dashboard
# Author: Tuan
# Icon: data:image/png;base64,
# DontUseFBInk

# ---------------------------------------------
#  CONFIGURATION
# ---------------------------------------------
PI_URL="http://100.116.165.30:5000/weather.png"
IMAGE_PATH="/mnt/us/weather.png"
LOG="/mnt/us/weather-dashboard.log"
TAILSCALE_BIN="/mnt/us/extensions/tailscale/bin"
REFRESH_SECS=1800          # 30 minutes between updates
WIFI_WAIT_SECS=20          # seconds to wait for WiFi
RETRY_WAIT_SECS=30         # seconds to wait before retrying a failed fetch
MAX_RETRIES=3              # how many times to retry a failed fetch
 
# ---------------------------------------------
#  LOGGING HELPER
# ---------------------------------------------
log() {
    echo "$(date '+%Y-%m-%d %H:%M:%S') $1" >> "$LOG"
}
 
# ---------------------------------------------
#  INIT
# ---------------------------------------------
log "=== Weather Dashboard starting ==="
 
# Stop the Kindle UI for a clean full-screen display
stop lab126_gui 2>/dev/null
stop framework  2>/dev/null
 
# Prevent the screensaver from kicking in
lipc-set-prop -i com.lab126.powerd preventScreenSaver 1
 
# Drop to powersave CPU governor to save energy
echo powersave > /sys/devices/system/cpu/cpu0/cpufreq/scaling_governor 2>/dev/null
 
log "Framework stopped, screensaver disabled."
 
# ---------------------------------------------
#  WIFI HELPER
# ---------------------------------------------
ensure_wifi() {
    lipc-set-prop -i com.lab126.cmd wirelessEnable 1
 
    local waited=0
    while [ $waited -lt $WIFI_WAIT_SECS ]; do
        IP=$(ifconfig wlan0 2>/dev/null | grep "inet addr" | awk -F: '{print $2}' | awk '{print $1}')
        if [ -n "$IP" ]; then
            log "WiFi up: $IP"
            return 0
        fi
        sleep 2
        waited=$((waited + 2))
    done
 
    # Toggle WiFi off/on and wait again
    log "WiFi not up after ${WIFI_WAIT_SECS}s - toggling..."
    lipc-set-prop -i com.lab126.cmd wirelessEnable 0
    sleep 5
    lipc-set-prop -i com.lab126.cmd wirelessEnable 1
    sleep 15
 
    IP=$(ifconfig wlan0 2>/dev/null | grep "inet addr" | awk -F: '{print $2}' | awk '{print $1}')
    if [ -n "$IP" ]; then
        log "WiFi up after toggle: $IP"
        return 0
    fi
 
    log "WiFi failed to connect."
    return 1
}
 
# ---------------------------------------------
#  SOCKS5 HELPER
# ---------------------------------------------
ensure_socks5() {
    if nc -z 127.0.0.1 1055 2>/dev/null; then
        log "SOCKS5 proxy already up."
        return 0
    fi
 
    log "SOCKS5 not running - starting tailscaled..."
    pkill tailscaled 2>/dev/null
    sleep 2
    nohup ${TAILSCALE_BIN}/tailscaled \
        --tun=userspace-networking \
        --socks5-server=127.0.0.1:1055 \
        --statedir=${TAILSCALE_BIN}/ \
        > ${TAILSCALE_BIN}/tailscaled.log 2>&1 &
    sleep 8
    ${TAILSCALE_BIN}/tailscale up 2>/dev/null
    sleep 3
 
    if nc -z 127.0.0.1 1055 2>/dev/null; then
        log "SOCKS5 proxy up."
        return 0
    fi
 
    log "SOCKS5 proxy failed to start."
    return 1
}
 
# ---------------------------------------------
#  FETCH HELPER
# ---------------------------------------------
fetch_image() {
    local attempt=1
    while [ $attempt -le $MAX_RETRIES ]; do
        log "Fetching image (attempt $attempt)..."
        if curl -s --proxy "socks5h://127.0.0.1:1055" -m 15 \
            -o "${IMAGE_PATH}.tmp" "$PI_URL"; then
            mv "${IMAGE_PATH}.tmp" "$IMAGE_PATH"
            log "Fetch OK."
            return 0
        else
            log "Fetch failed (attempt $attempt)."
            rm -f "${IMAGE_PATH}.tmp"
            attempt=$((attempt + 1))
            [ $attempt -le $MAX_RETRIES ] && sleep $RETRY_WAIT_SECS
        fi
    done
    log "All fetch attempts failed."
    return 1
}
 
# ---------------------------------------------
#  DISPLAY HELPER
# ---------------------------------------------
display_image() {
    if [ ! -f "$IMAGE_PATH" ]; then
        log "No image to display."
        eips -c
        eips 5 20 "No image - check Pi server"
        return 1
    fi
 
    # Clear screen twice to eliminate ghosting, then full refresh
    eips -c
    eips -c
    eips -f -g "$IMAGE_PATH"
    log "Image displayed."
}
 
# ---------------------------------------------
#  SLEEP HELPER
# ---------------------------------------------
do_sleep() {
    local sleep_secs="$1"
    log "Sleeping for ${sleep_secs}s..."
    sleep "$sleep_secs"
    log "Sleep done."
}
 
# ---------------------------------------------
#  STARTUP MESSAGE
# ---------------------------------------------
eips -c
eips 5 20 "Weather Dashboard starting..."
eips 5 22 "Fetching from Pi server..."
 
# ---------------------------------------------
#  MAIN LOOP
# ---------------------------------------------
while true; do
    CYCLE_START=$(date +%s)
 
    # 1. Make sure WiFi is up
    if ensure_wifi; then
        # 2. Make sure SOCKS5 proxy is up
        if ensure_socks5; then
            # 3. Fetch the latest image from the Pi
            fetch_image
        else
            log "Skipping fetch - SOCKS5 unavailable."
        fi
    else
        log "Skipping fetch - no WiFi."
    fi
 
    # 4. Display whatever we have
    display_image
 
    # 5. Calculate remaining sleep time
    CYCLE_END=$(date +%s)
    ELAPSED=$((CYCLE_END - CYCLE_START))
    SLEEP_TIME=$((REFRESH_SECS - ELAPSED))
    [ $SLEEP_TIME -lt 60 ] && SLEEP_TIME=60
 
    log "Cycle done in ${ELAPSED}s. Sleeping ${SLEEP_TIME}s."
 
    # 6. Sleep until next refresh
    do_sleep $SLEEP_TIME
done